{
    // gjoa: serve the custom forced-dark newtab page for home + newtab, never the
    // built-in activity-stream addon. FF152 removed the AboutNewTab.newTabURL
    // hook, so this redirector is the only override point. Returned directly (not
    // suspended on addon init) since the gjoa page has no built-in-addon dependency.
    if (
      uri.spec.startsWith("about:home") ||
      uri.spec.startsWith("about:newtab")
    ) {
      let gjoaChannel = Services.io.newChannelFromURIWithLoadInfo(
        Services.io.newURI("chrome://gjoa-newtab/content/newtab.html"),
        loadInfo
      );
      gjoaChannel.originalURI = uri;
      return gjoaChannel;
    }

    let chromeURI = this.getChromeURI(uri);
    let resultChannel = Services.io.newChannelFromURIWithLoadInfo(
      chromeURI,
      loadInfo
    );
    resultChannel.originalURI = uri;

    if (!this.#addonInitialized) {
      return this.#getSuspendedChannel(resultChannel);
    }

    return resultChannel;
  }

{
    if (!IS_PRIVILEGED_PROCESS) {
      throw Components.Exception(
        "newChannel can only be called from the privilegedabout content process.",
        Cr.NS_ERROR_UNEXPECTED
      );
    }

    // gjoa: serve the custom forced-dark newtab page for home + newtab, never the
    // built-in activity-stream addon or the (activity-stream) about:home startup
    // cache. disqualifyCache() drops any stale cached activity-stream document.
    if (
      uri.spec.startsWith("about:home") ||
      uri.spec.startsWith("about:newtab")
    ) {
      AboutHomeStartupCacheChild.disqualifyCache();
      let gjoaChannel = Services.io.newChannelFromURIWithLoadInfo(
        Services.io.newURI("chrome://gjoa-newtab/content/newtab.html"),
        loadInfo
      );
      gjoaChannel.originalURI = uri;
      return gjoaChannel;
    }

    let pageURI = this.getChromeURI(uri);
    let resultChannel = Services.io.newChannelFromURIWithLoadInfo(
      pageURI,
      loadInfo
    );
    resultChannel.originalURI = uri;
    return resultChannel;
  }
